mapper.select:
SELECT i.id, i.part_code, i.part_name, i.part_type, CASE i.part_type WHEN 'fan' THEN '风扇' WHEN 'capacitor' THEN '电容' WHEN 'board' THEN '板卡' WHEN 'other' THEN '其他' ELSE '未知' END AS part_type_desc, i.part_model, i.brand, i.specification, i.unit, i.unit_price, i.quantity, i.safe_quantity, i.min_purchase_quantity, i.quantity * i.unit_price AS total_amount, i.storage_location, i.warehouse, i.supplier, i.manufacturer, i.station_id, i.station_name, i.status, CASE i.status WHEN 0 THEN '停用' WHEN 1 THEN '启用' ELSE '未知' END AS status_desc, i.warn_status, CASE i.warn_status WHEN 0 THEN '正常' WHEN 1 THEN '低库存预警' WHEN 2 THEN '库存不足' ELSE '未知' END AS warn_status_desc, i.qr_code_url, i.remark, i.create_time, i.update_time FROM spare_part_inventory i WHERE i.deleted = 0
AND i.station_id IN
#{stationId}
AND ( i.part_name LIKE CONCAT('%', #{query.keyword}, '%') OR i.part_code LIKE CONCAT('%', #{query.keyword}, '%') OR i.part_model LIKE CONCAT('%', #{query.keyword}, '%') OR i.brand LIKE CONCAT('%', #{query.keyword}, '%') )
AND i.part_type = #{query.partType}
AND i.warehouse = #{query.warehouse}
AND i.warn_status = #{query.warnStatus}
AND i.status = #{query.status}
ORDER BY i.create_time DESC
